// Build OS Query (replace whole jsCode)

const size = 1000;


const queries = [
  { index: "cluster_summaries", existsField: "summary" },
  { index: "mega_summaries", existsField: "mega_summary" },
  { index: "news_cluster_summaries", existsField: "summary" },
  { index: "category_label", existsField: "category" },
];

return queries.map(({ index, existsField }) => {
  const query = {
    bool: {
      must: [{ exists: { field: existsField } }],
    },
  };

  return {
    json: {
      _meta: { index, size, existsField },
      os_query: {
        size,
        _source: [
          "cluster_id",
          "article_ids",
          "summary",
          "mega_summary",
          "category",
          "processed_at",
          "language",
        ],
        query,
        sort: [{ processed_at: { order: "desc" } }],
      },
    },
  };
});

const inputs = $input.all();

const out = [];

for (const it of inputs) {
  const res = it.json ?? {};
  const hits = res?.hits?.hits ?? [];

  for (const h of hits) {
    out.push({
      json: {
        os_index: h._index,
        doc_id: h._id,


        ...(h._source ?? {}),


        _hit: {
          _index: h._index,
          _id: h._id,
          _score: h._score ?? null,
        },
      },
    });
  }
}

return out;

const now = new Date().toISOString();
console.log("Translation workflow finished");

return [{
  json: {
    log_data: {
      request_id: `translation_run_${now}`.replace(/[:.]/g, "-"),
      source: "translation_workflow",
      endpoint: "run_summary",
      http_method: "N/A",
      status: "success",
      created_at: now,
      triggered_by: "n8n",
      payload_excerpt: { note: "Translation workflow completed" }
    }
  }
}];

return $input.all().map(it => {
  const j = it.json ?? {};
  return {
    json: {
      meta: j.meta,  
    }
  };
});

// Prepare Translate Payload - 推荐结构（确保 Save 阶段有 meta）

const items = $input.all();
const TARGET_LANG = "de";

const RULES = {
  cluster_summaries: {
    sourceField: "summary",
    targetField: "summary_translated",
    targetLangField: "summary_translated_language",
  },
  mega_summaries: {
    sourceField: "mega_summary",
    targetField: "mega_summary_translated",
    targetLangField: "mega_summary_translated_language",
  },
  news_cluster_summaries: {
    sourceField: "summary",
    targetField: "summary_translated",
    targetLangField: "summary_translated_language",
  },
  category_label: {
    sourceField: "category",
    targetField: "category_translated",
    targetLangField: "category_translated_language",
  },
};

return items.map((it) => {
  const j = it.json ?? {};
  const os_index = String(j.os_index ?? j._hit?._index ?? j._index ?? "cluster_summaries");
  const rule = RULES[os_index];
  if (!rule) throw new Error(`No rule for os_index=${os_index}`);

  const doc_id = String(j.doc_id ?? j._hit?._id ?? j._id ?? j.cluster_id ?? "").trim();
  if (!doc_id) throw new Error(`Missing doc_id for index=${os_index}`);

  const srcText = String(j[rule.sourceField] ?? "").trim();
  if (!srcText) throw new Error(`Missing ${rule.sourceField} for doc_id=${doc_id} index=${os_index}`);

  return {
    json: {
      meta: {
        os_index,
        doc_id,
        rule,               
        target_language: TARGET_LANG,
      },
      // endpoint 需要的输入
      payload: {
        cluster_summary: {
          summary: srcText,
          cluster_id: String(j.cluster_id ?? doc_id),
          article_ids: Array.isArray(j.article_ids) ? j.article_ids : [],
        },
      },
    },
  };
});

const now = new Date().toISOString();

function get(obj, path) {
  let cur = obj;
  for (const k of path) {
    if (cur == null) return undefined;
    cur = cur[k];
  }
  return cur;
}

return $input.all().map(it => {
  const j = it.json ?? {};

  const meta = j.meta ?? {};
  const doc_id = String(meta.doc_id ?? "").trim();
  const os_index = String(meta.os_index ?? "").trim();
  const rule = meta.rule;

  if (!doc_id || !os_index || !rule?.targetField || !rule?.targetLangField) {
    throw new Error(`Missing meta for save. keys=${Object.keys(j).join(",")}`);
  }

  const translated = String(
    get(j, ["payload", "cluster_summary", "summary_de"]) ??
    get(j, ["body", "payload", "cluster_summary", "summary_de"]) ??
    ""
  ).trim();

  if (!translated) {
    throw new Error(`Missing summary_de. doc_id=${doc_id} os_index=${os_index}`);
  }

  return {
    json: {
      doc_id,
      os_index,
      update_body: {
        doc: {
          [rule.targetField]: translated,
          [rule.targetLangField]: "de",
          translated_processed_at: now,
        },
        doc_as_upsert: true,
      },
    },
  };
});
